import React, { useState } from "react";
import {
  TextField,
  Button,
  Box,
  Typography,
  MenuItem,
  CircularProgress,
  Paper,
} from "@mui/material";
import OpenAI from "openai";

function ScriptForm() {
  const [topic, setTopic] = useState("");
  const [tone, setTone] = useState("Funny");
  const [loading, setLoading] = useState(false);
  const [script, setScript] = useState("");

  const client = new OpenAI({
    apiKey: process.env.REACT_APP_OPENAI_API_KEY,
    dangerouslyAllowBrowser: true, // for MVP only (not for production)
  });

  const handleGenerate = async () => {
    setLoading(true);
    setScript("");
    try {
      const completion = await client.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "user",
            content: `Generate a YouTube script for topic: "${topic}".
            Structure it as: Hook, Body, CTA.
            Tone: ${tone}.`,
          },
        ],
      });

      setScript(completion.choices[0].message.content);
    } catch (error) {
      console.error(error);
      setScript("⚠️ Error generating script. Check API key or usage.");
    }
    setLoading(false);
  };

  return (
    <Box sx={{ mt: 4 }}>
      <TextField
        fullWidth
        label="Enter video topic"
        value={topic}
        onChange={(e) => setTopic(e.target.value)}
        margin="normal"
      />

      <TextField
        select
        fullWidth
        label="Select Tone"
        value={tone}
        onChange={(e) => setTone(e.target.value)}
        margin="normal"
      >
        <MenuItem value="Funny">Funny</MenuItem>
        <MenuItem value="Serious">Serious</MenuItem>
        <MenuItem value="Inspirational">Inspirational</MenuItem>
        <MenuItem value="Edgy">Edgy</MenuItem>
      </TextField>

      <Button
        variant="contained"
        color="primary"
        onClick={handleGenerate}
        disabled={loading || !topic}
        sx={{ mt: 2 }}
      >
        {loading ? <CircularProgress size={24} /> : "Generate Script"}
      </Button>

      {script && (
        <Paper sx={{ mt: 4, p: 3, whiteSpace: "pre-wrap", bgcolor: "#f5f5f5" }}>
          <Typography variant="h6">Generated Script:</Typography>
          <Typography variant="body1">{script}</Typography>
        </Paper>
      )}
    </Box>
  );
}

export default ScriptForm;
